export interface {{props.resource}} {
  id: string;
  name: string;
  description: string;
  price: number;
  createdAt: Date;
  updatedAt: Date;
}

import { {{props.resource}} } from './model';

const items: Map<string, {{props.resource}}> = new Map();

export async function find{{props.resource}}ById(id: string): Promise<{{props.resource}} | null> {
  return items.get(id) || null;
}

export async function list{{props.resource}}s(): Promise<{{props.resource}}[]> {
  return Array.from(items.values());
}

export async function create{{props.resource}}(data: Omit<{{props.resource}}, 'id' | 'createdAt' | 'updatedAt'>): Promise<{{props.resource}}> {
  const item: {{props.resource}} = {
    ...data,
    id: crypto.randomUUID(),
    createdAt: new Date(),
    updatedAt: new Date()
  };
  items.set(item.id, item);
  return item;
}

export async function update{{props.resource}}(id: string, data: Partial<{{props.resource}}>): Promise<{{props.resource}} | null> {
  const existing = items.get(id);
  if (!existing) return null;
  const updated = { ...existing, ...data, updatedAt: new Date() };
  items.set(id, updated);
  return updated;
}

export async function delete{{props.resource}}(id: string): Promise<boolean> {
  return items.delete(id);
}

import { Router } from 'express';
import * as service from './service';

export const router = Router();

router.get('/{{props.path}}', async (req, res) => {
  const items = await service.list{{props.resource}}s();
  res.json(items);
});

router.get('/{{props.path}}/:id', async (req, res) => {
  const item = await service.find{{props.resource}}ById(req.params.id);
  if (!item) return res.status(404).json({ error: 'Not found' });
  res.json(item);
});

router.post('/{{props.path}}', async (req, res) => {
  const item = await service.create{{props.resource}}(req.body);
  res.status(201).json(item);
});

router.put('/{{props.path}}/:id', async (req, res) => {
  const item = await service.update{{props.resource}}(req.params.id, req.body);
  if (!item) return res.status(404).json({ error: 'Not found' });
  res.json(item);
});

router.delete('/{{props.path}}/:id', async (req, res) => {
  const deleted = await service.delete{{props.resource}}(req.params.id);
  res.status(deleted ? 204 : 404).send();
});

export * from './model';
export * from './service';
export { router } from './routes';
